const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.QUEUE_NAME || 'payment_events';
const PREFETCH = Number(process.env.PREFETCH || 10);

async function chargePayment(payload) {
  console.log('Charging payment', {
    paymentId: payload.paymentId,
    amount: payload.amount,
    currency: payload.currency,
    customerId: payload.customerId,
    source: payload.source,
  });

  await new Promise((resolve) => setTimeout(resolve, 300));

  return {
    status: 'charged',
    paymentId: payload.paymentId,
    processedAt: new Date().toISOString(),
  };
}

async function refundPayment(payload) {
  console.log('Refunding payment', {
    paymentId: payload.paymentId,
    amount: payload.amount,
    reason: payload.reason,
  });

  await new Promise((resolve) => setTimeout(resolve, 300));

  return {
    status: 'refunded',
    paymentId: payload.paymentId,
    processedAt: new Date().toISOString(),
  };
}

async function capturePayment(payload) {
  console.log('Capturing payment', {
    paymentId: payload.paymentId,
    authorizationId: payload.authorizationId,
    amount: payload.amount,
  });

  await new Promise((resolve) => setTimeout(resolve, 300));

  return {
    status: 'captured',
    paymentId: payload.paymentId,
    processedAt: new Date().toISOString(),
  };
}

async function processPaymentEvent(event) {
  switch (event.type) {
    case 'payment.charge':
      return chargePayment(event);
    case 'payment.refund':
      return refundPayment(event);
    case 'payment.capture':
      return capturePayment(event);
    default:
      throw new Error(`Unsupported payment event type: ${event.type}`);
  }
}

async function startConsumer() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  await channel.assertQueue(QUEUE_NAME, {
    durable: true,
  });

  await channel.prefetch(PREFETCH);

  console.log(`Waiting for payment events on queue "${QUEUE_NAME}"`);

  channel.consume(
    QUEUE_NAME,
    async (msg) => {
      if (!msg) return;

      try {
        const raw = msg.content.toString('utf8');
        const event = JSON.parse(raw);

        console.log('Received payment event', {
          deliveryTag: msg.fields.deliveryTag,
          type: event.type,
          paymentId: event.paymentId,
        });

        const result = await processPaymentEvent(event);

        console.log('Payment event processed successfully', result);
        channel.ack(msg);
      } catch (error) {
        console.error('Failed to process payment event', error);
        channel.nack(msg, false, false);
      }
    },
    {
      noAck: false,
    }
  );

  const shutdown = async () => {
    console.log('Shutting down consumer...');
    try {
      await channel.close();
    } catch (_) {}
    try {
      await connection.close();
    } catch (_) {}
    process.exit(0);
  };

  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);
}

startConsumer().catch((error) => {
  console.error('Consumer startup failed', error);
  process.exit(1);
});